        mImageWidth = width;
        mImageHeight = height;

        // If desired, set output resolution to source resolution
        if (width != 0 && height != 0 && mPipelineResolution == PipelineResolution.SOURCE) {
            getHolder().setFixedSize(width, height);
        }

